      const db = await getDb();
      await db.execute(
        'DELETE FROM recent_commands WHERE command_id = $1',
        [commandId],
      );
      await db.execute(
        'INSERT INTO recent_commands (command_id) VALUES ($1)',
        [commandId],
      );
      await db.execute(
        `DELETE FROM recent_commands WHERE id NOT IN (
          SELECT id FROM recent_commands ORDER BY used_at DESC LIMIT 10
        )`,
      );
      return;
    }
    const all = await this.getAll();
    const next = [commandId, ...all.filter(id => id !== commandId)].slice(0, 10);
    storageSet('recent-commands', next);
  },

  async clear(): Promise<void> {
    if (isTauri) {
      const db = await getDb();
      await db.execute('DELETE FROM recent_commands', []);
      return;
